"use client";

import { useEffect, useState } from "react";
import { getLiveGames } from "../lib/api";

export default function GameCard() {
  const [games, setGames] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    async function loadGames() {
      try {
        const data = await getLiveGames();
        setGames(data.response || []);
      } catch (err) {
        setError("Failed to load games");
      } finally {
        setLoading(false);
      }
    }
    loadGames();
  }, []);

  if (loading) return <div className="text-zinc-500 p-4">Loading games...</div>;
  if (error) return <div className="text-red-400 p-4">{error}</div>;
  if (games.length === 0) return <div className="text-zinc-500 p-4">No live games</div>;

  return (
    <div className="space-y-3">
      {games.map((game: any) => (
        <div key={game.id} className="bg-zinc-800/50 rounded-xl p-4 hover:bg-zinc-800 transition-colors">
          <div className="flex justify-between items-center mb-2">
            <span className="text-xs text-zinc-500">
              {game.status?.long || "Scheduled"}
            </span>
            <span className="text-xs text-zinc-500">
              Q{game.periods?.current || "-"}
            </span>
          </div>
          
          <div className="flex justify-between items-center">
            <div className="space-y-1">
              <p className="text-emerald-400 font-semibold text-sm">{game.teams?.home?.name}</p>
              <p className="text-zinc-400 text-sm">{game.teams?.visitors?.name}</p>
            </div>
            <div className="text-right space-y-1">
              <p className="text-white font-bold text-lg">{game.scores?.home?.points || "-"}</p>
              <p className="text-zinc-400 text-lg">{game.scores?.visitors?.points || "-"}</p>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}